import { devWarning, warning } from './warning';

let _isOverlaySupported: boolean;

export function isOverlaySupported(): boolean {
  // lazy load
  if (_isOverlaySupported !== undefined) {
    return _isOverlaySupported;
  }

  if (!(typeof window !== 'undefined' && window.document && window.document.createElement)) {
    return false;
  }

  const ele = document.createElement('div');
  ele.style.overflow = 'overlay';
  document.body.appendChild(ele);
  _isOverlaySupported = getComputedStyle(ele).overflow === 'overlay';
  document.body.removeChild(ele);

  return _isOverlaySupported;
}

export function parseLength(length: number | string, containerLength: number) {
  if (typeof length === 'number') {
    return length;
  }
  if (length.endsWith('%')) {
    return (parseFloat(length) * containerLength) / 100;
  }
  if (length.endsWith('px')) {
    return parseFloat(length);
  }
  warning(
    false,
    devWarning('parseLength', `length: ${length} is not valid, it can only accept pixel length and percent length.`),
  );
  return 0;
}

// 将 prefixCls='a b' 转换为 '.a .b'
export const prefixToSelector = (className: string) =>
  className
    .split(' ')
    .map(cls => `.${cls}`)
    .join(' ');
